trait Sound {
    fn make_sound(&self) -> &str;
}

struct Dog;
impl Sound for Dog {
    fn make_sound(&self) -> &str {
        "Woof"
    }
}

struct Cat;
impl Sound for Cat {
    fn make_sound(&self) -> &str {
        "Meow"
    }
}

fn main() {
    let animals: Vec<&dyn Sound> = vec![&Dog {}, &Cat {}];
    for a in animals {
        println!("{}", a.make_sound());
    }
}
